const { app } = require('@azure/functions');
const { CosmosClient } = require('@azure/cosmos');

const cosmosClient = new CosmosClient({
    endpoint: process.env.COSMOS_ENDPOINT,
    key: process.env.COSMOS_KEY
});

const database = cosmosClient.database(process.env.COSMOS_DATABASE);
const container = database.container(process.env.COSMOS_CONTAINER);

app.timer('batchDataProcessor', {
    schedule: '0 */30 * * * *',
    runOnStartup: false,
    handler: async (myTimer, context) => {
        const startTime = Date.now();
        context.log('Batch processing started at:', new Date().toISOString());

        try {
            let continuationToken = null;
            let totalProcessed = 0;
            let batchCount = 0;
            const batchSize = 100;

            do {
                const elapsedMinutes = (Date.now() - startTime) / 60000;
                if (elapsedMinutes > 9.5) {
                    context.log(`Approaching timeout limit. Processed ${totalProcessed} items in ${batchCount} batches.`);
                    break;
                }

                const querySpec = {
                    query: 'SELECT * FROM c WHERE c.processed = false OR NOT IS_DEFINED(c.processed)',
                    parameters: []
                };

                const options = {
                    maxItemCount: batchSize,
                    continuationToken: continuationToken
                };

                const { resources: items, continuationToken: nextToken, hasMoreResults } = await container.items
                    .query(querySpec, options)
                    .fetchNext();

                if (items && items.length > 0) {
                    batchCount++;
                    context.log(`Processing batch ${batchCount}: ${items.length} items`);

                    const processedItems = await processBatch(items, context);
                    
                    await updateProcessedItems(processedItems, context);

                    totalProcessed += items.length;
                    context.log(`Batch ${batchCount} completed. Total processed: ${totalProcessed}`);
                }

                continuationToken = nextToken;

                if (!hasMoreResults || !continuationToken) {
                    break;
                }

                await sleep(100);

            } while (continuationToken);

            const duration = (Date.now() - startTime) / 1000;
            context.log(`Batch processing completed. Total items: ${totalProcessed}, Duration: ${duration}s`);

            return {
                status: 'success',
                itemsProcessed: totalProcessed,
                batchesProcessed: batchCount,
                durationSeconds: duration
            };

        } catch (error) {
            context.log.error('Error in batch processing:', error);
            throw error;
        }
    }
});

