async function processBatch(items, context) {
    const processedItems = [];

    for (const item of items) {
        try {
            const processed = await processItem(item, context);
            processedItems.push(processed);
        } catch (error) {
            context.log.error(`Error processing item ${item.id}:`, error);
            processedItems.push({
                ...item,
                processed: false,
                processingError: error.message,
                lastProcessedAt: new Date().toISOString()
            });
        }
    }

    return processedItems;
}

async function processItem(item, context) {
    const transformedData = transformData(item);
    
    await performBusinessLogic(transformedData, context);
    
    const enrichedData = await enrichData(transformedData, context);
    
    return {
        ...item,
        ...enrichedData,
        processed: true,
        processedAt: new Date().toISOString()
    };
}

function transformData(item) {
    return {
        id: item.id,
        originalData: item,
        transformedValue: (item.value || 0) * 2,
        normalizedText: (item.text || '').toLowerCase().trim(),
        metadata: {
            source: item.source || 'unknown',
            category: item.category || 'default'
        }
    };
}

async function performBusinessLogic(data, context) {
    if (data.transformedValue > 1000) {
        data.metadata.highValue = true;
    }
    
    if (data.normalizedText.includes('urgent')) {
        data.metadata.priority = 'high';
    }
    
    await sleep(10);
    
    return data;
}

async function enrichData(data, context) {
    return {
        enrichmentTimestamp: new Date().toISOString(),
        calculatedScore: Math.random() * 100,
        validationStatus: 'validated',
        processingVersion: '1.0.0'
    };
}

async function updateProcessedItems(items, context) {
    const operations = items.map(item => ({
        operationType: 'Replace',
        resourceBody: item,
        partitionKey: item.partitionKey || item.id
    }));

    if (operations.length === 0) {
        return;
    }

    const chunkSize = 100;
    for (let i = 0; i < operations.length; i += chunkSize) {
        const chunk = operations.slice(i, i + chunkSize);
        
        try {
            for (const operation of chunk) {
                await container.item(operation.resourceBody.id, operation.partitionKey).replace(operation.resourceBody);
            }
            context.log(`Updated ${chunk.length} items in Cosmos DB`);
        } catch (error) {
            context.log.error('Error updating items:', error);
            throw error;
        }
        
        await sleep(50);
    }
}

function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}